#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, N;
        scanf("%lld %lld", &A, &N);
        long long totalSlices = N + 1;
        if (totalSlices % A != 0) {
            printf("-1\n");
        } else {
            printf("%lld\n", totalSlices / A);
        }
    }
    return 0;
}

